const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 12000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const body = $input.first().json.body || {};
const sb = $vars.CARGLASS_SUPABASE_URL;
const sbHeaders = { apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY };
async function fetchJson(url, opts) {
  const o = { ...(opts || {}) };
  o.headers = { ...sbHeaders, ...((opts && opts.headers) || {}) };
  const r = await fetch(url, o);
  if (!r.ok) throw new Error('Supabase ' + r.status + ': ' + (await r.text()));
  return await r.json();
}

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// ---------- Validate input ----------
const spoken_phone = String(body.spoken_phone || body.phone || '').trim();
const start_time = body.start_time || body.preferred_start || body.scheduled_start;
let branch_id = body.branch_id || body.branch || '';
let service_id = body.service_id || body.service || '';
const confirmation_token = body.confirmation_token;
const glass_type_raw = String(body.glass_type || '').trim().toLowerCase();
const damage_size_raw = String(body.damage_size || '').trim().toLowerCase();

if (!confirmation_token) {
  return [{ json: { ok: false, error_code: 'MISSING_CONFIRMATION', message_for_agent: 'Bitte erst die Buchung verbal bestätigen, dann erneut aufrufen mit confirmation_token.' } }];
}
if (!spoken_phone) {
  return [{ json: { ok: false, error_code: 'MISSING_PHONE', message_for_agent: 'Telefonnummer fehlt.' } }];
}
if (!start_time) {
  return [{ json: { ok: false, error_code: 'MISSING_TIME', message_for_agent: 'Bitte einen konkreten Termin (start_time) angeben.' } }];
}
if (!branch_id) {
  return [{ json: { ok: false, error_code: 'MISSING_BRANCH', message_for_agent: 'Filiale erforderlich.' } }];
}

// ---------- Normalize damage_size + glass_type ----------
const GLASS_MAP = {
  windshield: 'windshield', front: 'windshield', frontscheibe: 'windshield', windschutz: 'windshield', windschutzscheibe: 'windshield',
  side: 'side', seite: 'side', seitenscheibe: 'side',
  rear: 'rear', heck: 'rear', heckscheibe: 'rear', back: 'rear',
};
const SIZE_MAP = {
  small: 'small', klein: 'small', chip: 'small', steinschlag: 'small',
  medium: 'medium', mittel: 'medium', mid: 'medium',
  large: 'large', gross: 'large', "groß": 'large', big: 'large', riss: 'large', crack: 'large',
};
const glass_type = GLASS_MAP[glass_type_raw] || (glass_type_raw === '' ? null : glass_type_raw);
const damage_size = SIZE_MAP[damage_size_raw] || (damage_size_raw === '' ? null : null);

// ---------- Derive service_id from glass_type + damage_size if not provided ----------
if (!service_id) {
  if (!glass_type) {
    return [{ json: { ok: false, error_code: 'MISSING_PARAMS', message_for_agent: 'Glass-Typ oder service_id erforderlich.' } }];
  }
  let derivedCode;
  if (glass_type === 'windshield') {
    derivedCode = (damage_size === 'small') ? 'CG-FR' : 'CG-FA';
  } else if (glass_type === 'side') {
    derivedCode = 'CG-SS';
  } else if (glass_type === 'rear') {
    derivedCode = 'CG-HS';
  } else {
    return [{ json: { ok: false, error_code: 'UNSUPPORTED_GLASS', message_for_agent: `Glass-Typ '${glass_type}' nicht unterstützt.` } }];
  }
  const sv = await fetchJson(`${sb}/rest/v1/services?code=eq.${derivedCode}&select=id&limit=1`);
  if (!sv.length) return [{ json: { ok: false, error_code: 'SERVICE_NOT_FOUND', message_for_agent: `Service ${derivedCode} nicht gefunden.` } }];
  service_id = sv[0].id;
}

// ---------- Normalize phone to E.164 (DE default) ----------
function normalizePhone(s) {
  let v = String(s).replace(/[\s\-()]/g, '');
  const defaultCC = ($vars.CARGLASS_DEFAULT_COUNTRY_CODE || '+49');
  if (v.startsWith('00')) v = '+' + v.slice(2);
  else if (v.startsWith('0')) v = defaultCC + v.slice(1);
  else if (!v.startsWith('+')) v = defaultCC + v;
  return v;
}
const phone_e164 = normalizePhone(spoken_phone);

// ---------- Resolve branch slug → UUID ----------
if (!UUID_RE.test(String(branch_id))) {
  const term = String(branch_id).trim().toLowerCase();
  const enc = encodeURIComponent(term);
  const found = await fetchJson(`${sb}/rest/v1/branches?select=id,name,city,code&or=(code.ilike.${enc},name.ilike.*${enc}*,city.ilike.*${enc}*)&limit=1`);
  if (!found.length) return [{ json: { ok: false, error_code: 'BRANCH_NOT_FOUND', message_for_agent: `Filiale '${branch_id}' nicht gefunden.` } }];
  branch_id = found[0].id;
}

// ---------- Resolve service slug → UUID (only if user passed a slug) ----------
if (!UUID_RE.test(String(service_id))) {
  const term = String(service_id).trim().toLowerCase();
  const enc = encodeURIComponent(term);
  let found = await fetchJson(`${sb}/rest/v1/services?select=id,code&code=eq.${enc}&limit=1`);
  if (!found.length) found = await fetchJson(`${sb}/rest/v1/services?select=id,code,name_de,name_en&or=(name_de.ilike.*${enc}*,name_en.ilike.*${enc}*)&limit=1`);
  if (!found.length) return [{ json: { ok: false, error_code: 'SERVICE_NOT_FOUND', message_for_agent: `Service '${service_id}' nicht gefunden.` } }];
  service_id = found[0].id;
}

// ---------- Get service duration ----------
const services = await fetchJson(`${sb}/rest/v1/services?id=eq.${service_id}&select=default_duration_minutes,name_de`);
const durationMin = services[0]?.default_duration_minutes || 90;

// ---------- Validate / parse start_time ----------
const start = new Date(start_time);
if (isNaN(start.getTime())) return [{ json: { ok: false, error_code: 'INVALID_TIME', message_for_agent: 'Ungültige Uhrzeit.' } }];
const now = new Date();
if (start <= now) return [{ json: { ok: false, error_code: 'TIME_IN_PAST', message_for_agent: 'Der Termin liegt in der Vergangenheit.' } }];
const end = new Date(start.getTime() + durationMin * 60000);

// ---------- Upsert customer ----------
const existingCust = await fetchJson(`${sb}/rest/v1/customers?phone_e164=eq.${encodeURIComponent(phone_e164)}&select=id,first_name,last_name`);
let customer_id;
let customer_was_created = false;
function splitName(n) {
  if (!n) return { fn: null, ln: null };
  const parts = String(n).trim().split(/\s+/);
  if (parts.length === 1) return { fn: parts[0], ln: null };
  return { fn: parts[0], ln: parts.slice(1).join(' ') };
}
const incoming = body.first_name ? { fn: body.first_name, ln: body.last_name || null } : splitName(body.name);
if (existingCust.length) {
  customer_id = existingCust[0].id;
  if ((!existingCust[0].first_name || !existingCust[0].last_name) && (incoming.fn || incoming.ln)) {
    await fetchJson(`${sb}/rest/v1/customers?id=eq.${customer_id}`, {
      method: 'PATCH', headers: { Prefer: 'return=minimal' },
      body: {
        first_name: existingCust[0].first_name || incoming.fn || null,
        last_name: existingCust[0].last_name || incoming.ln || null,
        postal_code: body.postal_code || null,
      },
    });
  }
} else {
  const created = await fetchJson(`${sb}/rest/v1/customers`, {
    method: 'POST', headers: { Prefer: 'return=representation' },
    body: {
      phone_e164,
      first_name: incoming.fn,
      last_name: incoming.ln,
      postal_code: body.postal_code || null,
      language: body.language || 'de',
      consent_recording: true,
      consent_data_processing: true,
    },
  });
  customer_id = created[0].id;
  customer_was_created = true;
}

// ---------- Upsert vehicle (license_plate optional in new flow) ----------
let vehicle_id = null;
const vehMake = body.vehicle_make || body.make || null;
const vehModel = body.vehicle_model || body.model || null;
const vehYear = body.vehicle_year || body.year || null;
const vehPlate = body.license_plate ? String(body.license_plate).toUpperCase().replace(/\s+/g, '') : null;
const vehGlass = (glass_type === 'windshield') ? 'windshield' : (glass_type === 'side') ? 'side' : (glass_type === 'rear') ? 'rear' : null;

if (vehPlate) {
  // Match by plate first
  const exV = await fetchJson(`${sb}/rest/v1/vehicles?customer_id=eq.${customer_id}&license_plate=eq.${encodeURIComponent(vehPlate)}&select=id`);
  if (exV.length) vehicle_id = exV[0].id;
}
if (!vehicle_id && (vehMake || vehModel)) {
  // Match by make+model+year if no plate
  const params = [`customer_id=eq.${customer_id}`];
  if (vehMake)  params.push(`make=eq.${encodeURIComponent(vehMake)}`);
  if (vehModel) params.push(`model=eq.${encodeURIComponent(vehModel)}`);
  if (vehYear)  params.push(`year=eq.${vehYear}`);
  params.push('select=id');
  const exV = await fetchJson(`${sb}/rest/v1/vehicles?${params.join('&')}`);
  if (exV.length) vehicle_id = exV[0].id;
}
if (!vehicle_id && (vehPlate || vehMake || vehModel || vehYear || vehGlass)) {
  const vc = await fetchJson(`${sb}/rest/v1/vehicles`, {
    method: 'POST', headers: { Prefer: 'return=representation' },
    body: {
      customer_id,
      license_plate: vehPlate,
      make: vehMake,
      model: vehModel,
      year: vehYear ? Number(vehYear) : null,
      glass_type: vehGlass,
    },
  });
  vehicle_id = vc[0].id;
}

// ---------- Generate booking reference ----------
function genRef() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let s = '';
  for (let i = 0; i < 5; i++) s += chars[Math.floor(Math.random() * chars.length)];
  return 'CG-' + s;
}
let booking_reference;
for (let attempt = 0; attempt < 5; attempt++) {
  booking_reference = genRef();
  const exists = await fetchJson(`${sb}/rest/v1/appointments?booking_reference=eq.${booking_reference}&select=id&limit=1`);
  if (!exists.length) break;
}

// ---------- Insert appointment ----------
const appt = await fetchJson(`${sb}/rest/v1/appointments`, {
  method: 'POST', headers: { Prefer: 'return=representation' },
  body: {
    booking_reference,
    customer_id,
    vehicle_id,
    branch_id,
    service_id,
    scheduled_start: start.toISOString(),
    scheduled_end: end.toISOString(),
    status: 'scheduled',
    insurance_provider: body.insurance_provider || null,
    damage_size: damage_size,
    damage_notes: body.damage_notes || null,
    notes: body.notes || null,
    created_via: 'bot',
  },
});
const appointment = appt[0];

// History row
await fetchJson(`${sb}/rest/v1/appointment_history`, {
  method: 'POST', headers: { Prefer: 'return=minimal' },
  body: {
    appointment_id: appointment.id,
    previous_status: null,
    new_status: 'scheduled',
    new_start: start.toISOString(),
    changed_by: 'bot',
    conversation_id: null,
    reason: 'New booking via voicebot — confirmation_token: ' + confirmation_token,
  },
});

// ---------- Branch info for confirmation ----------
const br = await fetchJson(`${sb}/rest/v1/branches?id=eq.${branch_id}&select=name,city,address_line1`);

return [{ json: {
  ok: true,
  data: {
    booking_reference,
    appointment_id: appointment.id,
    customer_id,
    customer_was_created,
    vehicle_id,
    branch: br[0] || null,
    service_name: services[0]?.name_de || null,
    glass_type,
    damage_size,
    scheduled_start: start.toISOString(),
    scheduled_end: end.toISOString(),
    duration_minutes: durationMin,
    message_for_agent: `Termin erfolgreich gebucht. Buchungsnummer: ${booking_reference}.`,
  },
} }];
